const PiranhaMessage = require("../../PiranhaMessage")

class BookmarkListMessage extends PiranhaMessage {
  constructor(client) {
    super()
    this.id = 29377
    this.client = client
    this.version = 1
  }

  async encode() {
    // no bookmarks
    /*this.writeHex(
      "00000000",
    )*/

    this.writeHex(
      ""
    )
  }
}

module.exports = BookmarkListMessage